function Bomb(input) {
    const lines = input.trim().split('\n');
    const T = parseInt(lines[0]); // Number of test cases

    let index = 1; // Index to iterate through test cases

    // Iterate through each test case
    for (let t = 0; t < T; t++) {
        const [n1, x] = lines[index++].split(' ').map(Number); // N: Number of houses, X: Bomb attack strength
        const defenceStrengths = lines[index++].split(' ').map(Number); // Defence strengths of each house
        var maxDestroyed = 0;
        for(let j =0;j<n1;j++){
            if(defenceStrengths[j]<x){
                maxDestroyed = j+1;
            }
        }
        console.log(maxDestroyed); // Output maximum number of houses that can get destroyed for this test case
    }
}

